const lead = $('Batch 10 Leads').item.json;
const company = $json?.id ? $json : {};

return {
  json: {
    lead_id: lead.id,
    email: lead.properties?.email?.value,
    firstname: lead.properties?.firstname?.value,
    lastname: lead.properties?.lastname?.value,
    jobtitle: lead.properties?.jobtitle?.value || '',
    company_name: lead.properties?.company?.value || '',
    // Clearbit enrichment
    company_size: company.metrics?.employees || 0,
    company_industry: company.category?.industry || '',
    company_funding: company.metrics?.raised || 0,
    tech_stack: (company.tech || []).slice(0, 10).join(', '),
    company_growth: company.metrics?.employeesRange || '',
    // Engagement
    email_opens: parseInt(lead.properties?.hs_email_open?.value || 0),
    email_clicks: parseInt(lead.properties?.hs_email_click?.value || 0),
    conversions: parseInt(lead.properties?.num_conversion_events?.value || 0),
    notes_count: parseInt(lead.properties?.num_notes?.value || 0)
  }
};

