const ai = JSON.parse($json.message.content);
const ctx = $('Build Scoring Context').item.json;

// Weighted final score
const icp_component = ai.icp_score * 4;  // 40 pts max
const engagement_component = Math.min((ctx.email_opens * 2 + ctx.email_clicks * 3 + ctx.conversions * 5), 30); // 30 pts max
const company_size_component = ctx.company_size >= 50 && ctx.company_size <= 500 ? 20 : ctx.company_size > 500 ? 10 : 5; // 20 pts max
const timing_component = ctx.notes_count > 0 ? 10 : 0; // 10 pts

const final_score = Math.round(icp_component + engagement_component + company_size_component + timing_component);
const tier = final_score >= 80 ? 'A' : final_score >= 60 ? 'B' : final_score >= 40 ? 'C' : 'D';

return {
  json: {
    lead_id: ctx.lead_id,
    email: ctx.email,
    final_score,
    tier,
    icp_score: ai.icp_score,
    key_signals: ai.key_fit_signals?.join(', '),
    concerns: ai.key_concerns?.join(', '),
    rationale: ai.rationale,
    scored_at: new Date().toISOString()
  }
};
